const candidateData = $fromAI('candidateData', 'Candidate performance and validation data to check against policy rules', 'json');
const policyRules = $fromAI('policyRules', 'Institutional policy rules for promotion eligibility', 'json');

try {
  const data = typeof candidateData === 'string' ? JSON.parse(candidateData) : candidateData;
  const rules = typeof policyRules === 'string' ? JSON.parse(policyRules) : policyRules;

  // Policy compliance checks
  const checks = {
    minimumYearsInRank: data.yearsInCurrentRank >= (rules.minYearsInRank || 5),
    requiredPublications: data.researchOutputsCount >= (rules.minPublications || 5),
    teachingRequirement: data.teachingEvaluationScore >= (rules.minTeachingScore || 7.5),
    serviceRequirement: data.serviceContributionsCount >= (rules.minServiceContributions || 3),
    noEthicsViolations: !data.ethicsViolations || data.ethicsViolations.length === 0,
    departmentApproval: data.departmentApprovalStatus === 'APPROVED'
  };

  const allChecksPassed = Object.values(checks).every(check => check === true);
  const failedChecks = Object.keys(checks).filter(key => checks[key] === false);

  const result = {
    complianceStatus: allChecksPassed ? 'COMPLIANT' : 'NON_COMPLIANT',
    checks: checks,
    failedChecks: failedChecks,
    policyViolations: failedChecks.map(check => `Failed: ${check}`),
    recommendation: allChecksPassed ? 'Proceed with promotion' : 'Address policy violations before proceeding',
    verificationDate: new Date().toISOString()
  };

  return JSON.stringify(result, null, 2);

} catch (error) {
  return JSON.stringify({
    complianceStatus: 'ERROR',
    error: 'Policy compliance check failed',
    message: error.message
  });
}
